560   // At this point, Sizes contains the absolute step recurrences for all
561   // induction variables. Each step recurrence must be a multiple of the size of
562   // the array element. Assuming that the each value represents the size of an
563   // array for each dimension, attempts to restore the length of each dimension
564   // by dividing the step recurrence by the next smaller value. For example, if
565   // we have the following AddRec SCEV:
566   //
567   //   AddRec: {{{0,+,2048}<%for.i>,+,256}<%for.j>,+,8}<%for.k> (ElementSize=8)
568   //
569   // Then Sizes will become [256, 32, 1] after sorted. We don't know the size of
570   // the outermost dimension, the next dimension will be computed as 256 / 32 =
571   // 8, and the last dimension will be computed as 32 / 1 = 32. Thus it results
572   // in like Arr[UnknownSize][8][32] with elements of size 8 bytes, where Arr is
573   // a base pointer.
574   //
575   // TODO: Catch more cases, e.g., when a step recurrence is not divisible by
576   // the next smaller one, like A[i][3*j].
577   llvm::sort(Sizes.rbegin(), Sizes.rend());
578   Sizes.erase(llvm::unique(Sizes), Sizes.end());
579 
580   // The last element in Sizes should be ElementSize. At this point, all values
581   // in Sizes are assumed to be divided by ElementSize, so replace it with 1.
582   assert(Sizes.back() != 0 && "Unexpected zero size in Sizes.");
583   Sizes.back() = 1;
584 
585   for (unsigned I = 0; I + 1 < Sizes.size(); I++) {
586     uint64_t PrevSize = Sizes[I + 1];
587     if (Sizes[I] % PrevSize) {
588       Sizes.clear();
589       return false;
590     }
591     Sizes[I] /= PrevSize;
592   }
593 
594   // Finally, the last element in Sizes should be ElementSize.
595   Sizes.back() = *ElementSizeConst;
596   return true;
597 }
