639 /// Splits the SCEV into two vectors of SCEVs representing the subscripts and
640 /// sizes of an array access, assuming that the array is a fixed size array.
641 ///
642 /// E.g., if we have the code like as follows:
643 ///
644 ///  double A[42][8][32];
645 ///  for i
646 ///    for j
647 ///      for k
648 ///        use A[i][j][k]
649 ///
650 /// The access function will be represented as an AddRec SCEV like:
651 ///
652 ///  AddRec: {{{0,+,2048}<%for.i>,+,256}<%for.j>,+,8}<%for.k> (ElementSize=8)
653 ///
654 /// Then findFixedSizeArrayDimensions infers the size of each dimension of the
655 /// array based on the fact that the value of the step recurrence is a multiple
656 /// of the size of the corresponding array element. In the above example, it
657 /// results in the following:
658 ///
659 ///  CHECK: ArrayDecl[UnknownSize][8][32] with elements of 8 bytes.
660 ///
661 /// Finally each subscript will be computed as follows:
662 ///
663 ///  CHECK: ArrayRef[{0,+,1}<%for.i>][{0,+,1}<%for.j>][{0,+,1}<%for.k>]
664 ///
665 /// Note that this function doesn't check the range of possible values for each
666 /// subscript, so the caller should perform additional boundary checks if
667 /// necessary.
668 ///
669 /// Also note that this function doesn't guarantee that the original array size
670 /// is restored "correctly". For example, in the following case:
671 ///
672 ///  double A[42][4][64];
673 ///  double B[42][8][32];
674 ///  for i
675 ///    for j
676 ///      for k
677 ///        use A[i][j][k]
678 ///        use B[i][2*j][k]
679 ///
680 /// The access function for both accesses will be the same:
681 ///
682 ///  AddRec: {{{0,+,2048}<%for.i>,+,512}<%for.j>,+,8}<%for.k> (ElementSize=8)
683 ///
684 /// The array sizes for both A and B will be computed as
685 /// ArrayDecl[UnknownSize][4][64], which matches for A, but not for B.
686 ///
687 /// TODO: At the moment, this function can handle only simple cases. For
688 /// example, we cannot handle a case where a step recurrence is not divisible
689 /// by the next smaller step recurrence, e.g., A[i][3*j].
690 bool llvm::delinearizeFixedSizeArray(ScalarEvolution &SE, const SCEV *Expr,
691                                      SmallVectorImpl<const SCEV *> &Subscripts,
692                                      SmallVectorImpl<const SCEV *> &Sizes,
693                                      const SCEV *ElementSize) {
694   // Clear output vectors.
695   Subscripts.clear();
696   Sizes.clear();
697 
698   const SCEVUnknown *BasePointer =
699       dyn_cast<SCEVUnknown>(SE.getPointerBase(Expr));
700   const SCEV *Offset = BasePointer ? SE.getMinusSCEV(Expr, BasePointer) : Expr;
701 
702   // First step: find the fixed array size.
703   SmallVector<uint64_t, 4> ConstSizes;
704   if (!findFixedSizeArrayDimensions(SE, Offset, ConstSizes, ElementSize)) {
705     Sizes.clear();
706     return false;
707   }
708 
709   // Convert the constant size to SCEV.
710   for (uint64_t Size : ConstSizes)
711     Sizes.push_back(SE.getConstant(Offset->getType(), Size));
712 
713   // Maybe we can extract the outer dimension from the global variable
714   // declaration.
715   if (BasePointer)
716     extractOuterDimFromGlobal(SE, BasePointer->getValue(), Sizes, ElementSize);
717 
718   // Second step: compute the access functions for each subscript.
719   computeAccessFunctions(SE, Offset, Subscripts, Sizes);
720 
721   return !Subscripts.empty();
722 }
723 
724 bool llvm::validateDelinearizationResult(ScalarEvolution &SE,
725                                          ArrayRef<const SCEV *> Sizes,
726                                          ArrayRef<const SCEV *> Subscripts) {
727   // Sizes and Subscripts are as follows:
728   //
729   //   Sizes:      [UNK][S_2]...[S_n]
730   //   Subscripts: [I_1][I_2]...[I_n]
731   //
732   // where the size of the outermost dimension is unknown (UNK).
733 
734   auto AddOverflow = [&](const SCEV *A, const SCEV *B) -> const SCEV * {
735     if (!SE.willNotOverflow(Instruction::Add, /*IsSigned=*/true, A, B))
736       return nullptr;
737     return SE.getAddExpr(A, B);
738   };
739 
740   auto MulOverflow = [&](const SCEV *A, const SCEV *B) -> const SCEV * {
741     if (!SE.willNotOverflow(Instruction::Mul, /*IsSigned=*/true, A, B))
742       return nullptr;
743     return SE.getMulExpr(A, B);
744   };
745 
746   // Range check: 0 <= I_k < S_k for k = 2..n.
747   for (size_t I = 1; I < Sizes.size(); ++I) {
748     const SCEV *Size = Sizes[I - 1];
749     const SCEV *Subscript = Subscripts[I];
750     if (!SE.isKnownNonNegative(Subscript))
751       return false;
752 
753     // TODO: It may be better that delinearization itself unifies the types of
754     // all elements in Sizes and Subscripts.
755     Type *WiderTy = SE.getWiderType(Subscript->getType(), Size->getType());
756     Subscript = SE.getNoopOrSignExtend(Subscript, WiderTy);
757     Size = SE.getNoopOrSignExtend(Size, WiderTy);
758     if (!SE.isKnownPredicate(ICmpInst::ICMP_SLT, Subscript, Size)) {
759       LLVM_DEBUG(dbgs() << "Range check failed: " << *Subscript << " <s "
760                         << *Size << "\n");
761       return false;
762     }
763   }
764 
765   // The offset computation is as follows:
766   //
767   //   Offset = I_n +
768   //            S_n * I_{n-1} +
769   //            ... +
770   //            (S_2 * ... * S_n) * I_1
771   //
772   // Regarding this as a function from (I_1, I_2, ..., I_n) to integers, it
773   // must be injective. To guarantee it, the above calculation must not
774   // overflow. Since we have already checked that 0 <= I_k < S_k for k = 2..n,
775   // the minimum and maximum values occur in the following cases:
776   //
777   //   Min = [I_1][0]...[0] = S_2 * ... * S_n * I_1
778   //   Max = [I_1][S_2-1]...[S_n-1]
779   //       = (S_2 * ... * S_n) * I_1 +
780   //         (S_2 * ... * S_{n-1}) * (S_2 - 1) +
781   //         ... +
782   //         (S_n - 1)
783   //       = (S_2 * ... * S_n) * I_1 +
784   //         (S_2 * ... * S_n) - 1  (can be proven by induction)
785   //       = Min + (S_2 * ... * S_n) - 1
786   //
787   // NOTE: I_1 can be negative, so Min is not just 0.
788   const SCEV *Prod = SE.getOne(Sizes[0]->getType());
789   for (const SCEV *Size : Sizes) {
790     Prod = MulOverflow(Prod, Size);
791     if (!Prod)
792       return false;
793   }
794   const SCEV *Min = MulOverflow(Prod, Subscripts[0]);
795   if (!Min)
796     return false;
797 
798   // We have already checked that Min and Prod don't overflow, so it's enough
799   // to check whether Min + Prod - 1 doesn't overflow.
