348 void llvm::computeAccessFunctions(ScalarEvolution &SE, const SCEV *Expr,
349                                   SmallVectorImpl<const SCEV *> &Subscripts,
350                                   SmallVectorImpl<const SCEV *> &Sizes) {
351   // Early exit in case this SCEV is not an affine multivariate function.
352   if (Sizes.empty())
353     return;
354 
355   if (auto *AR = dyn_cast<SCEVAddRecExpr>(Expr))
356     if (!AR->isAffine())
357       return;
358 
359   // Clear output vector.
360   Subscripts.clear();
361 
362   LLVM_DEBUG(dbgs() << "\ncomputeAccessFunctions\n"
363                     << "Memory Access Function: " << *Expr << "\n");
364 
365   const SCEV *Res = Expr;
366   int Last = Sizes.size() - 1;
367 
368   for (int i = Last; i >= 0; i--) {
369     const SCEV *Size = Sizes[i];
370     const SCEV *Q, *R;
371 
372     SCEVDivision::divide(SE, Res, Size, &Q, &R);
373 
374     LLVM_DEBUG({
375       dbgs() << "Computing 'MemAccFn / Sizes[" << i << "]':\n";
376       dbgs() << "  MemAccFn: " << *Res << "\n";
377       dbgs() << "  Sizes[" << i << "]: " << *Size << "\n";
378       dbgs() << "  Quotient (Leftover): " << *Q << "\n";
379       dbgs() << "  Remainder (Subscript Access Function): " << *R << "\n";
380     });
381 
382     Res = Q;
383 
384     // Do not record the last subscript corresponding to the size of elements in
385     // the array.
386     if (i == Last) {
387 
388       // Bail out if the byte offset is non-zero.
389       if (!R->isZero()) {
390         Subscripts.clear();
391         Sizes.clear();
392         return;
393       }
394 
395       continue;
396     }
397 
398     // Record the access function for the current subscript.
399     Subscripts.push_back(R);
400   }
401 
402   if (!Res->isZero()) {
403     // This is only needed when the outermost array size is not known.  Res = 0
404     // when the outermost array dimension is known, as for example when reading
405     // array sizes from a local or global declaration.
406     Subscripts.push_back(Res);
407     LLVM_DEBUG(dbgs() << "Subscripts push_back Res: " << *Res << "\n");
408   }
409 
410   std::reverse(Subscripts.begin(), Subscripts.end());
411 
412   LLVM_DEBUG({
413     dbgs() << "Subscripts:\n";
414     for (const SCEV *S : Subscripts)
415       dbgs().indent(2) << *S << "\n";
416     dbgs() << "\n";
417   });
418 }
