420 /// Splits the SCEV into two vectors of SCEVs representing the subscripts and
421 /// sizes of an array access. Returns the remainder of the delinearization that
422 /// is the offset start of the array.  The SCEV->delinearize algorithm computes
423 /// the multiples of SCEV coefficients: that is a pattern matching of sub
424 /// expressions in the stride and base of a SCEV corresponding to the
425 /// computation of a GCD (greatest common divisor) of base and stride.  When
426 /// SCEV->delinearize fails, it returns the SCEV unchanged.
427 ///
428 /// For example: when analyzing the memory access A[i][j][k] in this loop nest
429 ///
430 ///  void foo(long n, long m, long o, double A[n][m][o]) {
431 ///
432 ///    for (long i = 0; i < n; i++)
433 ///      for (long j = 0; j < m; j++)
434 ///        for (long k = 0; k < o; k++)
435 ///          A[i][j][k] = 1.0;
436 ///  }
437 ///
438 /// the delinearization input is the following AddRec SCEV:
439 ///
440 ///  AddRec: {{{%A,+,(8 * %m * %o)}<%for.i>,+,(8 * %o)}<%for.j>,+,8}<%for.k>
441 ///
442 /// From this SCEV, we are able to say that the base offset of the access is %A
443 /// because it appears as an offset that does not divide any of the strides in
444 /// the loops:
445 ///
446 ///  CHECK: Base offset: %A
447 ///
448 /// and then SCEV->delinearize determines the size of some of the dimensions of
449 /// the array as these are the multiples by which the strides are happening:
450 ///
451 ///  CHECK: ArrayDecl[UnknownSize][%m][%o] with elements of sizeof(double)
452 ///  bytes.
453 ///
454 /// Note that the outermost dimension remains of UnknownSize because there are
455 /// no strides that would help identifying the size of the last dimension: when
456 /// the array has been statically allocated, one could compute the size of that
457 /// dimension by dividing the overall size of the array by the size of the known
458 /// dimensions: %m * %o * 8.
459 ///
460 /// Finally delinearize provides the access functions for the array reference
461 /// that does correspond to A[i][j][k] of the above C testcase:
462 ///
463 ///  CHECK: ArrayRef[{0,+,1}<%for.i>][{0,+,1}<%for.j>][{0,+,1}<%for.k>]
464 ///
465 /// The testcases are checking the output of a function pass:
466 /// DelinearizationPass that walks through all loads and stores of a function
467 /// asking for the SCEV of the memory access with respect to all enclosing
468 /// loops, calling SCEV->delinearize on that and printing the results.
469 void llvm::delinearize(ScalarEvolution &SE, const SCEV *Expr,
470                        SmallVectorImpl<const SCEV *> &Subscripts,
471                        SmallVectorImpl<const SCEV *> &Sizes,
472                        const SCEV *ElementSize) {
473   // Clear output vectors.
474   Subscripts.clear();
475   Sizes.clear();
476 
477   // First step: collect parametric terms.
478   SmallVector<const SCEV *, 4> Terms;
479   collectParametricTerms(SE, Expr, Terms);
480 
481   if (Terms.empty())
482     return;
483 
484   // Second step: find subscript sizes.
485   findArrayDimensions(SE, Terms, Sizes, ElementSize);
486 
487   if (Sizes.empty())
488     return;
489 
490   // Third step: compute the access functions for each subscript.
491   computeAccessFunctions(SE, Expr, Subscripts, Sizes);
492 }
