494 static std::optional<APInt> tryIntoAPInt(const SCEV *S) {
495   if (const auto *Const = dyn_cast<SCEVConstant>(S))
496     return Const->getAPInt();
497   return std::nullopt;
498 }
499 
500 /// Collects the absolute values of constant steps for all induction variables.
501 /// Returns true if we can prove that all step recurrences are constants and \p
502 /// Expr is divisible by \p ElementSize. Each step recurrence is stored in \p
503 /// Steps after divided by \p ElementSize.
504 static bool collectConstantAbsSteps(ScalarEvolution &SE, const SCEV *Expr,
505                                     SmallVectorImpl<uint64_t> &Steps,
506                                     uint64_t ElementSize) {
507   // End of recursion. The constant value also must be a multiple of
508   // ElementSize.
509   if (const auto *Const = dyn_cast<SCEVConstant>(Expr)) {
510     const uint64_t Mod = Const->getAPInt().urem(ElementSize);
511     return Mod == 0;
512   }
513 
514   const SCEVAddRecExpr *AR = dyn_cast<SCEVAddRecExpr>(Expr);
515   if (!AR || !AR->isAffine())
516     return false;
517 
518   const SCEV *Step = AR->getStepRecurrence(SE);
519   std::optional<APInt> StepAPInt = tryIntoAPInt(Step);
520   if (!StepAPInt)
521     return false;
522 
523   APInt Q;
524   uint64_t R;
525   APInt::udivrem(StepAPInt->abs(), ElementSize, Q, R);
526   if (R != 0)
527     return false;
528 
529   // Bail out when the step is too large.
530   std::optional<uint64_t> StepVal = Q.tryZExtValue();
531   if (!StepVal)
532     return false;
533 
534   Steps.push_back(*StepVal);
535   return collectConstantAbsSteps(SE, AR->getStart(), Steps, ElementSize);
536 }
