690 bool llvm::delinearizeFixedSizeArray(ScalarEvolution &SE, const SCEV *Expr,
691                                      SmallVectorImpl<const SCEV *> &Subscripts,
692                                      SmallVectorImpl<const SCEV *> &Sizes,
693                                      const SCEV *ElementSize) {
694   // Clear output vectors.
695   Subscripts.clear();
696   Sizes.clear();
697 
698   const SCEVUnknown *BasePointer =
699       dyn_cast<SCEVUnknown>(SE.getPointerBase(Expr));
700   const SCEV *Offset = BasePointer ? SE.getMinusSCEV(Expr, BasePointer) : Expr;
701 
702   // First step: find the fixed array size.
703   SmallVector<uint64_t, 4> ConstSizes;
704   if (!findFixedSizeArrayDimensions(SE, Offset, ConstSizes, ElementSize)) {
705     Sizes.clear();
706     return false;
707   }
708 
709   // Convert the constant size to SCEV.
710   for (uint64_t Size : ConstSizes)
711     Sizes.push_back(SE.getConstant(Offset->getType(), Size));
712 
713   // Maybe we can extract the outer dimension from the global variable
714   // declaration.
715   if (BasePointer)
716     extractOuterDimFromGlobal(SE, BasePointer->getValue(), Sizes, ElementSize);
717 
718   // Second step: compute the access functions for each subscript.
719   computeAccessFunctions(SE, Offset, Subscripts, Sizes);
720 
721   return !Subscripts.empty();
722 }
