724 bool llvm::validateDelinearizationResult(ScalarEvolution &SE,
725                                          ArrayRef<const SCEV *> Sizes,
726                                          ArrayRef<const SCEV *> Subscripts) {
727   // Sizes and Subscripts are as follows:
728   //
729   //   Sizes:      [UNK][S_2]...[S_n]
730   //   Subscripts: [I_1][I_2]...[I_n]
731   //
732   // where the size of the outermost dimension is unknown (UNK).
733 
734   auto AddOverflow = [&](const SCEV *A, const SCEV *B) -> const SCEV * {
735     if (!SE.willNotOverflow(Instruction::Add, /*IsSigned=*/true, A, B))
736       return nullptr;
737     return SE.getAddExpr(A, B);
738   };
739 
740   auto MulOverflow = [&](const SCEV *A, const SCEV *B) -> const SCEV * {
741     if (!SE.willNotOverflow(Instruction::Mul, /*IsSigned=*/true, A, B))
742       return nullptr;
743     return SE.getMulExpr(A, B);
744   };
745 
746   // Range check: 0 <= I_k < S_k for k = 2..n.
747   for (size_t I = 1; I < Sizes.size(); ++I) {
748     const SCEV *Size = Sizes[I - 1];
749     const SCEV *Subscript = Subscripts[I];
750     if (!SE.isKnownNonNegative(Subscript))
751       return false;
752 
753     // TODO: It may be better that delinearization itself unifies the types of
754     // all elements in Sizes and Subscripts.
755     Type *WiderTy = SE.getWiderType(Subscript->getType(), Size->getType());
756     Subscript = SE.getNoopOrSignExtend(Subscript, WiderTy);
757     Size = SE.getNoopOrSignExtend(Size, WiderTy);
758     if (!SE.isKnownPredicate(ICmpInst::ICMP_SLT, Subscript, Size)) {
759       LLVM_DEBUG(dbgs() << "Range check failed: " << *Subscript << " <s "
760                         << *Size << "\n");
761       return false;
762     }
763   }
764 
765   // The offset computation is as follows:
766   //
767   //   Offset = I_n +
768   //            S_n * I_{n-1} +
769   //            ... +
770   //            (S_2 * ... * S_n) * I_1
771   //
772   // Regarding this as a function from (I_1, I_2, ..., I_n) to integers, it
773   // must be injective. To guarantee it, the above calculation must not
774   // overflow. Since we have already checked that 0 <= I_k < S_k for k = 2..n,
775   // the minimum and maximum values occur in the following cases:
776   //
777   //   Min = [I_1][0]...[0] = S_2 * ... * S_n * I_1
778   //   Max = [I_1][S_2-1]...[S_n-1]
779   //       = (S_2 * ... * S_n) * I_1 +
780   //         (S_2 * ... * S_{n-1}) * (S_2 - 1) +
781   //         ... +
782   //         (S_n - 1)
783   //       = (S_2 * ... * S_n) * I_1 +
784   //         (S_2 * ... * S_n) - 1  (can be proven by induction)
785   //       = Min + (S_2 * ... * S_n) - 1
786   //
787   // NOTE: I_1 can be negative, so Min is not just 0.
788   const SCEV *Prod = SE.getOne(Sizes[0]->getType());
789   for (const SCEV *Size : Sizes) {
790     Prod = MulOverflow(Prod, Size);
791     if (!Prod)
792       return false;
793   }
794   const SCEV *Min = MulOverflow(Prod, Subscripts[0]);
795   if (!Min)
796     return false;
797 
798   // We have already checked that Min and Prod don't overflow, so it's enough
799   // to check whether Min + Prod - 1 doesn't overflow.
800   const SCEV *MaxPlusOne = AddOverflow(Min, Prod);
801   if (!MaxPlusOne)
802     return false;
803   if (!SE.willNotOverflow(Instruction::Sub, /*IsSigned=*/true, MaxPlusOne,
804                           SE.getOne(MaxPlusOne->getType())))
805     return false;
806 
807   return true;
808 }
