810 bool llvm::getIndexExpressionsFromGEP(ScalarEvolution &SE,
811                                       const GetElementPtrInst *GEP,
812                                       SmallVectorImpl<const SCEV *> &Subscripts,
813                                       SmallVectorImpl<const SCEV *> &Sizes) {
814   assert(Subscripts.empty() && Sizes.empty() &&
815          "Expected output lists to be empty on entry to this function.");
816   assert(GEP && "getIndexExpressionsFromGEP called with a null GEP");
817   LLVM_DEBUG(dbgs() << "\nGEP to delinearize: " << *GEP << "\n");
818   Type *Ty = nullptr;
819   Type *IndexTy = SE.getEffectiveSCEVType(GEP->getPointerOperandType());
820   bool DroppedFirstDim = false;
821   for (unsigned i = 1; i < GEP->getNumOperands(); i++) {
822     const SCEV *Expr = SE.getSCEV(GEP->getOperand(i));
823     if (i == 1) {
824       Ty = GEP->getSourceElementType();
825       if (auto *Const = dyn_cast<SCEVConstant>(Expr))
826         if (Const->getValue()->isZero()) {
827           DroppedFirstDim = true;
828           continue;
829         }
830       Subscripts.push_back(Expr);
831       continue;
832     }
833 
834     auto *ArrayTy = dyn_cast<ArrayType>(Ty);
835     if (!ArrayTy) {
836       LLVM_DEBUG(dbgs() << "GEP delinearize failed: " << *Ty
837                         << " is not an array type.\n");
838       Subscripts.clear();
839       Sizes.clear();
840       return false;
841     }
842 
843     Subscripts.push_back(Expr);
844     if (!(DroppedFirstDim && i == 2))
845       Sizes.push_back(SE.getConstant(IndexTy, ArrayTy->getNumElements()));
846 
847     Ty = ArrayTy->getElementType();
848   }
849   LLVM_DEBUG({
850     dbgs() << "Subscripts:\n";
851     for (const SCEV *S : Subscripts)
852       dbgs() << *S << "\n";
853     dbgs() << "\n";
854   });
855 
856   return !Subscripts.empty();
857 }
